"""GameList Visual Editor

Shrinks/fades Miyoo Mix-style preview art so it stops swallowing game list
text, and tweaks the list font size to match. Built after a lot of trial and
error figuring out how Onion actually lays out its game list screen.

Needs: Python + Pillow (pip install pillow). Tkinter ships with Python already.
Run: python gamelist_visual_editor.py
"""

import os
import io
import json
import base64
import shutil
import datetime
import threading
import tkinter as tk
from tkinter import ttk, filedialog, messagebox

from PIL import Image, ImageDraw, ImageFont, ImageTk


SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
SETTINGS_PATH = os.path.join(SCRIPT_DIR, "gamelist_editor_settings.json")

# Screen size + header/footer bar height per device. The header (system name +
# battery) and footer (button hints + page count) are both confirmed at 60px
# each on the 640x480 panel, straight from Onion's own theme assets -- and
# 480 - 60 - 60 = 360, which lines up exactly with the max artwork height.
# The Mini Flip's numbers are scaled proportionally from those, since its
# resolution is real but its UI bar heights haven't been confirmed the same way.
DEVICES = {
    "Miyoo Mini": {"screen": (640, 480), "header_h": 60, "footer_h": 60, "max_art_w": 250},
    "Miyoo Mini Plus": {"screen": (640, 480), "header_h": 60, "footer_h": 60, "max_art_w": 250},
    "Miyoo Flip / Flip V2": {"screen": (640, 480), "header_h": 60, "footer_h": 60, "max_art_w": 250},
    "Miyoo Mini Flip": {"screen": (750, 560), "header_h": 70, "footer_h": 70, "max_art_w": 293},
}

SAMPLE_IMAGE_B64 = """"""

ICON_A_B64 = """"""
ICON_B_B64 = """"""
ICON_BATTERY_B64 = """"""


def load_icon(b64_data):
    return Image.open(io.BytesIO(base64.b64decode(b64_data))).convert("RGBA")


BASE_TITLES = [
    "Dexterity",
    "Pokemon - Gold Version",
    "Pokemon - Crystal Version",
    "Pokemon - Silver Version",
    "Double Dragon II",
    "Dragon Warrior",
    "Donkey Kong Land",
    "Donkey Kong Land 2",
    "Donkey Kong Land III",
]
SELECTED_INDEX = 2

# These two are fixed -- in real Onion, the header (title.size) and footer
# (hint.size) fonts are independent values from the list font, so the preview
# shouldn't make them look like they change together when they don't.
HEADER_FONT_SIZE = 25
FOOTER_FONT_SIZE = 18


def load_sample_image():
    data = base64.b64decode(SAMPLE_IMAGE_B64)
    return Image.open(io.BytesIO(data)).convert("RGBA")


def adjust_image(img, target_height, opacity_percent):
    """Proportionally resize (not crop) + fade an RGBA image."""
    img = img.convert("RGBA")
    w, h = img.size
    if h != target_height and h > 0:
        scale = target_height / h
        img = img.resize((max(1, round(w * scale)), max(1, round(h * scale))), Image.LANCZOS)

    r, g, b, a = img.split()
    factor = max(0, min(100, opacity_percent)) / 100
    a = a.point(lambda p: int(p * factor))
    return Image.merge("RGBA", (r, g, b, a))


def process_image_file(src_path, dst_path, target_height, opacity_percent):
    img = Image.open(src_path)
    result = adjust_image(img, target_height, opacity_percent)
    os.makedirs(os.path.dirname(dst_path), exist_ok=True)
    result.save(dst_path, "PNG")


def build_mock_screen(artwork_img, font_size, screen_w, screen_h, header_h, footer_h, max_art_w):
    content_top = header_h
    content_bottom = screen_h - footer_h
    content_h = content_bottom - content_top

    row_h = max(20, round(56 * screen_h / 480))
    rows_needed = (content_h // row_h) + 2
    titles = []
    while len(titles) < rows_needed:
        titles.extend(BASE_TITLES)
    titles = titles[:rows_needed]

    canvas = Image.new("RGB", (screen_w, screen_h), "#1c1c1c")
    draw = ImageDraw.Draw(canvas)

    list_font = ImageFont.load_default(size=font_size)
    header_font = ImageFont.load_default(size=HEADER_FONT_SIZE)
    footer_font = ImageFont.load_default(size=FOOTER_FONT_SIZE)

    # header -- system name + battery icon, both fixed size regardless of list font
    draw.rectangle([0, 0, screen_w, header_h], fill="#101010")
    draw.text((20, header_h // 2), "NES", fill="#FFFFFF", font=header_font, anchor="lm")

    battery_icon = load_icon(ICON_BATTERY_B64).resize((28, 28))
    bat_x = screen_w - 20 - 45 - battery_icon.width
    bat_y = (header_h - battery_icon.height) // 2
    canvas.paste(battery_icon, (bat_x, bat_y), battery_icon)
    draw.text((screen_w - 20, header_h // 2), "86%", fill="#FFFFFF", font=footer_font, anchor="rm")

    # list rows, confined between the header and footer
    for i, title in enumerate(titles):
        y = content_top + i * row_h
        if y >= content_bottom:
            break
        selected = (i == SELECTED_INDEX)
        draw.rectangle([0, y, screen_w, min(y + row_h, content_bottom)],
                        fill="#7247c2" if selected else "#2a2a2a")
        draw.text((20, y + row_h // 2), title, fill="#FFFFFF" if selected else "#CCCCCC",
                   font=list_font, anchor="lm")

    # footer -- real A/B icons + hint text + page count, fixed size
    draw.rectangle([0, content_bottom, screen_w, screen_h], fill="#101010")
    foot_mid = content_bottom + footer_h // 2

    icon_a = load_icon(ICON_A_B64).resize((22, 22))
    icon_b = load_icon(ICON_B_B64).resize((22, 22))
    canvas.paste(icon_a, (20, foot_mid - 11), icon_a)
    draw.text((48, foot_mid), "SELECT", fill="#FFFFFF", font=footer_font, anchor="lm")
    canvas.paste(icon_b, (140, foot_mid - 11), icon_b)
    draw.text((168, foot_mid), "BACK", fill="#FFFFFF", font=footer_font, anchor="lm")

    draw.text((screen_w - 20, foot_mid), "2/568", fill="#FFFFFF", font=footer_font, anchor="rm")

    # artwork: scales around a FIXED center point (the middle of the full-size
    # box), instead of re-anchoring an edge as it shrinks. This is what keeps
    # it visually "in place" rather than drifting toward a corner as you adjust
    # the size slider -- matches what's actually observed on the real device.
    canvas = canvas.convert("RGBA")
    center_x = screen_w - max_art_w // 2
    center_y = content_top + content_h // 2
    aw, ah = artwork_img.size
    paste_x = center_x - aw // 2
    paste_y = center_y - ah // 2
    canvas.alpha_composite(artwork_img, (paste_x, paste_y))
    return canvas.convert("RGB")


def load_settings():
    try:
        with open(SETTINGS_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return {}


def save_settings(data):
    try:
        with open(SETTINGS_PATH, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2)
    except OSError:
        pass  # not critical if this fails, just skip remembering settings this time


class ScrollableFrame(tk.Frame):
    def __init__(self, parent):
        super().__init__(parent)
        canvas = tk.Canvas(self, borderwidth=0, highlightthickness=0)
        scrollbar = tk.Scrollbar(self, orient="vertical", command=canvas.yview)
        self.inner = tk.Frame(canvas)

        self.inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.create_window((0, 0), window=self.inner, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        canvas.bind_all("<MouseWheel>", lambda e: canvas.yview_scroll(int(-1 * (e.delta / 120)), "units"))


class App(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("GameList Visual Editor")
        self.geometry("700x920")
        self.resizable(True, True)
        self.protocol("WM_DELETE_WINDOW", self.on_close)

        self.settings = load_settings()
        self.sample_image = load_sample_image()
        self.custom_image = None
        self.using_custom_image = False
        self.font_warning_shown = False
        self._suppress_font_warning = False
        self.preview_photo = None

        scroll = ScrollableFrame(self)
        scroll.pack(fill="both", expand=True)
        root = scroll.inner
        pad = {"padx": 10, "pady": 6}

        # ---------------- LIVE PREVIEW ----------------
        preview_frame = tk.LabelFrame(root, text="Live Preview (approximate)", padx=5, pady=5)
        preview_frame.pack(fill="x", padx=10, pady=10)

        device_row = tk.Frame(preview_frame)
        device_row.pack(pady=(0, 5))
        tk.Label(device_row, text="Device:").pack(side="left", padx=5)
        self.device_var = tk.StringVar(value=self.settings.get("device", "Miyoo Mini Plus"))
        device_dropdown = ttk.Combobox(device_row, textvariable=self.device_var,
                                        values=list(DEVICES.keys()), state="readonly", width=22)
        device_dropdown.pack(side="left", padx=5)
        device_dropdown.bind("<<ComboboxSelected>>", lambda e: self.refresh_preview())

        self.preview_label = tk.Label(preview_frame)
        self.preview_label.pack(padx=10, pady=5)

        img_btn_row = tk.Frame(preview_frame)
        img_btn_row.pack(pady=5)
        tk.Button(img_btn_row, text="Use my own image...", command=self.browse_custom_image).pack(side="left", padx=5)
        tk.Button(img_btn_row, text="Reset to sample image", command=self.reset_sample_image).pack(side="left", padx=5)
        self.image_source_label = tk.Label(preview_frame, text="Using built-in sample image", fg="gray")
        self.image_source_label.pack()

        controls_row = tk.Frame(preview_frame)
        controls_row.pack(pady=5)

        tk.Label(controls_row, text="Target height (px, width scales to match):").grid(row=0, column=0, columnspan=2, padx=5)
        self.height_var = tk.IntVar(value=self.settings.get("height", 360))
        tk.Spinbox(controls_row, from_=50, to=420, textvariable=self.height_var, width=8,
                   command=self.refresh_preview).grid(row=1, column=0, padx=5)

        tk.Label(controls_row, text="Opacity (%):").grid(row=0, column=2, padx=15)
        self.opacity_var = tk.IntVar(value=self.settings.get("opacity", 100))
        tk.Spinbox(controls_row, from_=0, to=100, textvariable=self.opacity_var, width=8,
                   command=self.refresh_preview).grid(row=1, column=2, padx=15)

        tk.Label(controls_row, text="Font size:").grid(row=0, column=3, padx=15)
        self.font_size_var = tk.IntVar(value=self.settings.get("font_size", 25))
        tk.Spinbox(controls_row, from_=8, to=60, textvariable=self.font_size_var, width=8,
                   command=self.refresh_preview).grid(row=1, column=3, padx=15)

        self.height_var.trace_add("write", lambda *a: self.refresh_preview())
        self.opacity_var.trace_add("write", lambda *a: self.refresh_preview())
        self.font_size_var.trace_add("write", lambda *a: self.on_font_size_changed())

        # ---------------- APPLY TO IMAGES ----------------
        img_frame = tk.LabelFrame(root, text="Apply to Your Images", padx=5, pady=5)
        img_frame.pack(fill="x", padx=10, pady=10)

        tk.Label(img_frame, text="Source folder (Roms folder -- can contain multiple systems, all get processed):").grid(
            row=0, column=0, sticky="w", **pad)
        self.source_var = tk.StringVar(value=self.settings.get("source_dir", ""))
        tk.Entry(img_frame, textvariable=self.source_var, width=50).grid(row=1, column=0, **pad)
        tk.Button(img_frame, text="Browse...", command=self.browse_source).grid(row=1, column=1, **pad)

        tk.Label(img_frame, text="Output folder (processed copies go here, originals untouched):").grid(
            row=2, column=0, sticky="w", **pad)
        self.output_var = tk.StringVar(value=self.settings.get("output_dir", ""))
        tk.Entry(img_frame, textvariable=self.output_var, width=50).grid(row=3, column=0, **pad)
        tk.Button(img_frame, text="Browse...", command=self.browse_output).grid(row=3, column=1, **pad)

        self.run_button = tk.Button(img_frame, text="Confirm & Run on Real Images", command=self.run_clicked,
                                     bg="#4CAF50", fg="white", height=2)
        self.run_button.grid(row=4, column=0, columnspan=2, sticky="we", **pad)

        self.progress = ttk.Progressbar(img_frame, mode="determinate")
        self.progress.grid(row=5, column=0, columnspan=2, sticky="we", padx=10)

        tk.Label(img_frame, text="Processing log:").grid(row=6, column=0, columnspan=2, sticky="w", padx=10, pady=(10, 0))
        self.log_box = tk.Text(img_frame, height=6, width=68, state="disabled", bg="#f0f0f0")
        self.log_box.grid(row=7, column=0, columnspan=2, padx=10, pady=(0, 10))

        # ---------------- FONT SIZE -> THEME ----------------
        font_frame = tk.LabelFrame(root, text="Apply Font Size to Theme", padx=5, pady=5)
        font_frame.pack(fill="x", padx=10, pady=10)

        tk.Label(font_frame, text="Theme config.json (Themes/<YourTheme>/config.json):").grid(
            row=0, column=0, sticky="w", **pad)
        self.config_path_var = tk.StringVar(value=self.settings.get("config_path", ""))
        tk.Entry(font_frame, textvariable=self.config_path_var, width=50).grid(row=1, column=0, **pad)
        tk.Button(font_frame, text="Browse...", command=self.browse_config).grid(row=1, column=1, **pad)

        btn_row = tk.Frame(font_frame)
        btn_row.grid(row=2, column=0, columnspan=2, sticky="we", padx=10, pady=6)
        tk.Button(btn_row, text="Save Font Size", command=self.save_font_size,
                  bg="#2196F3", fg="white", height=2).pack(side="left", fill="x", expand=True, padx=(0, 5))
        tk.Button(btn_row, text="Restore from Backup", command=self.restore_font_backup,
                  bg="#9E9E9E", fg="white", height=2).pack(side="left", fill="x", expand=True, padx=(5, 0))

        self.font_status = tk.Label(font_frame, text="", fg="green")
        self.font_status.grid(row=3, column=0, columnspan=2, sticky="w", padx=10, pady=(0, 10))

        self.refresh_preview()

    # ---------------- PREVIEW ----------------

    def on_font_size_changed(self):
        self.refresh_preview()
        if not self._suppress_font_warning and not self.font_warning_shown:
            self.font_warning_shown = True
            messagebox.showinfo(
                "Heads up",
                "This only changes the preview.\n\n"
                "To actually apply it on your device, use 'Save Font Size' "
                "in the section below.",
            )

    def refresh_preview(self):
        try:
            device = DEVICES.get(self.device_var.get(), DEVICES["Miyoo Mini Plus"])
            screen_w, screen_h = device["screen"]
            source_img = self.custom_image if self.using_custom_image else self.sample_image
            artwork = adjust_image(source_img, self.height_var.get(), self.opacity_var.get())
            mock_screen = build_mock_screen(artwork, self.font_size_var.get(), screen_w, screen_h,
                                             device["header_h"], device["footer_h"], device["max_art_w"])
            display_h = 315
            display_w = round(display_h * screen_w / screen_h)
            self.preview_photo = ImageTk.PhotoImage(mock_screen.resize((display_w, display_h)))
            self.preview_label.config(image=self.preview_photo)
        except (tk.TclError, ValueError, ZeroDivisionError):
            pass

    def browse_custom_image(self):
        path = filedialog.askopenfilename(title="Select a preview image",
                                           filetypes=[("PNG images", "*.png")])
        if not path:
            return
        try:
            self.custom_image = Image.open(path).convert("RGBA")
            self.using_custom_image = True
            self.image_source_label.config(text=f"Using: {os.path.basename(path)}", fg="green")
            self.refresh_preview()
        except Exception as e:
            messagebox.showerror("Error", f"Couldn't load that image:\n{e}")

    def reset_sample_image(self):
        self.using_custom_image = False
        self.image_source_label.config(text="Using built-in sample image", fg="gray")
        self.refresh_preview()

    # ---------------- APPLY TO IMAGES ----------------

    def browse_source(self):
        path = filedialog.askdirectory(title="Select Roms folder")
        if path:
            self.source_var.set(path)

    def browse_output(self):
        path = filedialog.askdirectory(title="Select output folder")
        if path:
            self.output_var.set(path)

    def log(self, msg):
        self.log_box.config(state="normal")
        self.log_box.insert("end", msg + "\n")
        self.log_box.see("end")
        self.log_box.config(state="disabled")
        self.update_idletasks()

    def run_clicked(self):
        source = self.source_var.get().strip()
        output = self.output_var.get().strip()

        if not source or not os.path.isdir(source):
            messagebox.showerror("Error", "Please select a valid source folder.")
            return
        if not output:
            messagebox.showerror("Error", "Please select an output folder.")
            return

        self.run_button.config(state="disabled")
        self.log_box.config(state="normal")
        self.log_box.delete("1.0", "end")
        self.log_box.config(state="disabled")

        threading.Thread(target=self.process_all,
                          args=(source, output, self.height_var.get(), self.opacity_var.get()),
                          daemon=True).start()

    def process_all(self, source, output, target_height, opacity_percent):
        targets = []
        for r, dirs, files in os.walk(source):
            if os.path.basename(r) != "Imgs":
                continue
            for fname in files:
                if fname.lower().endswith(".png"):
                    targets.append(os.path.join(r, fname))

        if not targets:
            self.log("No Imgs folders found under that source folder.")
            self.log("Double check you picked the Roms folder, not a different one.")
            self.run_button.config(state="normal")
            messagebox.showwarning("Nothing to do", "No images were found. Check the source folder is right.")
            return

        self.progress["maximum"] = len(targets)
        self.progress["value"] = 0
        self.log(f"Found {len(targets)} images to process.\n")

        processed, errors = 0, []
        for src_path in targets:
            rel_path = os.path.relpath(src_path, source)
            dst_path = os.path.join(output, rel_path)
            try:
                process_image_file(src_path, dst_path, target_height, opacity_percent)
                processed += 1
            except Exception as e:
                self.log(f"FAILED: {rel_path} -> {e}")
                errors.append(f"{rel_path}: {e}")
            self.progress["value"] += 1
            self.update_idletasks()

        self.log("\nDone.")
        self.log(f"  Processed: {processed}")
        self.log(f"  Errors: {len(errors)}")
        self.log(f"  Output folder: {output}")

        log_path = self.write_summary(source, output, target_height, opacity_percent, processed, errors)
        self.log(f"  Summary saved to: {log_path}")

        self.run_button.config(state="normal")
        self.persist_settings()
        messagebox.showinfo("Finished", f"Processed {processed} images.\nErrors: {len(errors)}\n\nSummary saved alongside your output.")

    def write_summary(self, source, output, target_height, opacity_percent, processed, errors):
        timestamp = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
        log_path = os.path.join(output, f"run_summary_{timestamp}.txt")
        try:
            with open(log_path, "w", encoding="utf-8") as f:
                f.write("GameList Visual Editor -- run summary\n")
                f.write(f"Time: {timestamp}\n")
                f.write(f"Source: {source}\n")
                f.write(f"Output: {output}\n")
                f.write(f"Target height: {target_height}\n")
                f.write(f"Opacity: {opacity_percent}%\n")
                f.write(f"Processed: {processed}\n")
                f.write(f"Errors: {len(errors)}\n")
                if errors:
                    f.write("\nError details:\n")
                    for e in errors:
                        f.write(f"  {e}\n")
        except OSError:
            return "(couldn't write summary file)"
        return log_path

    # ---------------- FONT SIZE -> THEME ----------------

    def browse_config(self):
        path = filedialog.askopenfilename(title="Select config.json", filetypes=[("JSON files", "*.json")])
        if not path:
            return
        self.config_path_var.set(path)
        try:
            with open(path, "r", encoding="utf-8") as f:
                config = json.load(f)
            current_size = config.get("list", {}).get("size")
            if current_size is not None:
                self._suppress_font_warning = True
                self.font_size_var.set(current_size)
                self._suppress_font_warning = False
                self.font_status.config(text=f"Loaded current size: {current_size}", fg="green")
            else:
                self.font_status.config(text="Couldn't find list.size in this file -- wrong config.json?", fg="red")
        except Exception as e:
            self.font_status.config(text=f"Couldn't read file: {e}", fg="red")

    def save_font_size(self):
        path = self.config_path_var.get().strip()
        if not path or not os.path.isfile(path):
            messagebox.showerror("Error", "Please select a valid config.json file first.")
            return
        try:
            shutil.copy2(path, path + ".bak")
            with open(path, "r", encoding="utf-8") as f:
                config = json.load(f)
            config.setdefault("list", {})["size"] = self.font_size_var.get()
            with open(path, "w", encoding="utf-8") as f:
                json.dump(config, f, indent=4)
            self.font_status.config(text=f"Saved! New size: {self.font_size_var.get()} (backup made)", fg="green")
            self.persist_settings()
        except Exception as e:
            self.font_status.config(text=f"Failed to save: {e}", fg="red")
            messagebox.showerror("Error", f"Failed to save:\n{e}")

    def restore_font_backup(self):
        path = self.config_path_var.get().strip()
        backup = path + ".bak"
        if not path or not os.path.isfile(backup):
            messagebox.showerror("Error", "No backup found for this file yet.")
            return
        try:
            shutil.copy2(backup, path)
            with open(path, "r", encoding="utf-8") as f:
                config = json.load(f)
            restored_size = config.get("list", {}).get("size")
            if restored_size is not None:
                self._suppress_font_warning = True
                self.font_size_var.set(restored_size)
                self._suppress_font_warning = False
            self.font_status.config(text="Restored from backup.", fg="green")
        except Exception as e:
            self.font_status.config(text=f"Restore failed: {e}", fg="red")

    # ---------------- SETTINGS PERSISTENCE ----------------

    def persist_settings(self):
        save_settings({
            "device": self.device_var.get(),
            "height": self.height_var.get(),
            "opacity": self.opacity_var.get(),
            "font_size": self.font_size_var.get(),
            "source_dir": self.source_var.get(),
            "output_dir": self.output_var.get(),
            "config_path": self.config_path_var.get(),
        })

    def on_close(self):
        self.persist_settings()
        self.destroy()


if __name__ == "__main__":
    app = App()
    app.mainloop()
